fun solve(nums: Array<Long>, queries: Array<Array<Long>>): Array<Long> {
    val n = nums.size
    if (n == 0) {
        return Array(queries.size) { 0L }
    }

    // 1. Preprocessing: Calculate prefix sums of even numbers
    val p = LongArray(n)
    var currentCount = 0L
    for (i in 0 until n) {
        if (nums[i] % 2 == 0L) {
            currentCount++
        }
        p[i] = currentCount
    }

    // Helper function to find the index of the last element <= V in nums (upper_bound - 1)
    // Returns -1 if all elements are > V. Returns n-1 if all elements are <= V.
    fun getEffectiveUpperIndex(v: Long): Int {
        var low = 0
        var high = n - 1
        var result = -1
        while (low <= high) {
            val mid = low + (high - low) / 2
            if (nums[mid] <= v) {
                result = mid
                low = mid + 1
            } else {
                high = mid - 1
            }
        }
        return result
    }

    val results = mutableListOf<Long>()

    for (query in queries) {
        val l = query[0].toInt()
        val r = query[1].toInt()
        val k = query[2]

        // Binary search for M such that M - E_removed(2M) >= k
        // M must be at least 1. Max M is roughly k + N. Since k <= 10^9 and N <= 10^5, 
        // a safe upper bound R is 2*10^9 + 2.
        var L: Long = 1
        var R: Long = 2_000_000_000L + n + 2 // Safe upper bound for M
        var ansM: Long = R // Initialize to a large value

        while (L <= R) {
            val M = L + (R - L) / 2
            val V = 2 * M

            // 1. Find R_idx: Index of the last element in nums <= V
            val R_idx = getEffectiveUpperIndex(V)

            // 2. Determine the effective upper bound R_eff for the range [l, r]
            val R_eff = minOf(r, R_idx)

            var E_removed = 0L
            if (l <= R_eff) {
                // Count of even numbers in nums[l..R_eff]
                val countUpToR_eff = p[R_eff]
                val countBeforeL = if (l > 0) p[l - 1] else 0L
                E_removed = countUpToR_eff - countBeforeL
            }

            // Check condition: Count of remaining elements <= 2M must be >= k
            // Count = M - E_removed
            if (M - E_removed >= k) {
                // M might be the answer, try smaller
                ansM = M
                R = M - 1
            } else {
                // M is too small, need larger M
                L = M + 1
            }
        }

        results.add(2 * ansM)
    }

    return results.toTypedArray()
}

