fun solve(nums: Array<Long>, queries: Array<Array<Long>>): Array<Long> {
    val N = nums.size

    // Step 1: Preprocessing
    // E_nums stores all even numbers from nums in increasing order.
    val E_nums = mutableListOf<Long>()
    // J stores the original indices in nums corresponding to elements in E_nums.
    val J = mutableListOf<Int>()

    for (i in 0 until N) {
        if (nums[i] % 2 == 0L) {
            E_nums.add(nums[i])
            J.add(i)
        }
    }

    val P = E_nums.size

    // Helper functions for binary searching on sorted lists (Lower/Upper bound analogs)

    // Finds the index of the first element in sortedList >= target. Returns size if all elements are smaller.
    fun lowerBound(sortedList: List<Int>, target: Int): Int {
        var low = 0
        var high = sortedList.size
        while (low < high) {
            val mid = low + (high - low) / 2
            if (sortedList[mid] < target) {
                low = mid + 1
            } else {
                high = mid
            }
        }
        return low
    }

    // Finds the index of the first element in sortedList > target. Returns size if all elements are <= target.
    fun upperBound(sortedList: List<Int>, target: Int): Int {
        var low = 0
        var high = sortedList.size
        while (low < high) {
            val mid = low + (high - low) / 2
            if (sortedList[mid] <= target) {
                low = mid + 1
            } else {
                high = mid
            }
        }
        return low
    }

    // Finds the index of the first element in E_nums > X in the range [start, end] (inclusive).
    // Returns end + 1 if all elements in range are <= X.
    fun upperBoundLong(arr: List<Long>, X: Long, start: Int, end: Int): Int {
        var low = start
        var high = end + 1 // Search space is [start, end+1)
        var result = end + 1

        while (low < high) {
            val mid = low + (high - low) / 2
            if (arr[mid] > X) {
                result = mid
                high = mid
            } else {
                low = mid + 1
            }
        }
        return result
    }

    val ans = mutableListOf<Long>()

    // Step 2 & 3: Process Queries
    for (query in queries) {
        val L = query[0].toInt() // l_i
        val R = query[1].toInt() // r_i
        val K = query[2]        // k_i

        // 1. Determine the indices s and t in E_nums corresponding to the range [L, R] in nums.

        // s: index of first even number whose original index >= L
        val s = lowerBound(J, L)

        // t_plus_1: index of first even number whose original index > R
        val t_plus_1 = upperBound(J, R)
